-- Create "apns_configs" table
CREATE TABLE "public"."apns_configs" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "topic" character varying NOT NULL,
  "cert_file_path" character varying NOT NULL,
  "key_file_path" character varying NOT NULL,
  "expiry" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "apns_configs_topic_key" to table: "apns_configs"
CREATE UNIQUE INDEX "apns_configs_topic_key" ON "public"."apns_configs" ("topic");
-- Create "dep_tokens" table
CREATE TABLE "public"."dep_tokens" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
  "p7m_file_path" character varying NOT NULL,
  "expiry" timestamptz NULL,
  "last_used" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "dep_tokens_name_key" to table: "dep_tokens"
CREATE UNIQUE INDEX "dep_tokens_name_key" ON "public"."dep_tokens" ("name");
-- Create "users" table
CREATE TABLE "public"."users" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "username" character varying NOT NULL,
  "email" character varying NOT NULL,
  "password" character varying NOT NULL,
  "role" character varying NOT NULL DEFAULT 'USER',
  "status" character varying NOT NULL DEFAULT 'ACTIVE',
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "users_email_key" to table: "users"
CREATE UNIQUE INDEX "users_email_key" ON "public"."users" ("email");
-- Create index "users_username_key" to table: "users"
CREATE UNIQUE INDEX "users_username_key" ON "public"."users" ("username");
-- Create "devices" table
CREATE TABLE "public"."devices" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "serial_number" character varying NOT NULL,
  "model" character varying NOT NULL,
  "is_enrolled" boolean NOT NULL DEFAULT false,
  "name" character varying NULL,
  "last_sync" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "owner_id" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "devices_users_devices" FOREIGN KEY ("owner_id") REFERENCES "public"."users" ("id") ON UPDATE NO ACTION ON DELETE SET NULL
);
-- Create index "devices_serial_number_key" to table: "devices"
CREATE UNIQUE INDEX "devices_serial_number_key" ON "public"."devices" ("serial_number");
